  ('aboriginal-a5729396-moex-00324', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲男、乙女為夫妻，乙於婚姻關係存續中自丙男受胎而生下A。下列何者，欠缺當事人適格？', '["乙以甲與A為被告提起否認子女之訴", "甲以乙與丙為被告提起否認子女之訴", "A以甲為被告提起否認推定生父之訴", "若乙已死亡，甲以A為被告提起否認子女之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00325', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲向乙之住所地法院臺灣高雄地方法院提出請求返還借款之民事訴訟，審理中乙住所搬到臺中，乙抗 辯原法院已非管轄法院。下列敘述何者錯誤？', '["本件應移送臺灣臺中地方法院管轄", "本件仍由臺灣高雄地方法院審判", "法院不得經甲之同意，將本件移送臺灣臺中地方法院管轄", "法院就管轄權有無應依職權審酌，不必等待當事人抗辯 乙、刑事訴訟法部分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
