  ('aboriginal-a5729396-moex-00330', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於刑事訴訟基本原則之敘述，下列何者正確？', '["偵查中對證人應行交互詰問", "被告之自白，不得作為有罪判決之唯一證據", "被告沒有無罪推定原則的適用", "被告保持緘默，法官可以據此推斷被告有罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
