  ('aboriginal-a5729396-moex-00332', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '下列何者非發動刑事訴訟法第131條第1項無令狀搜索之法定事由？', '["因逮捕被告，有事實足認被告確實在住宅內者", "因執行拘提，有事實足認被告確實在住宅內者", "因執行令狀搜索違禁物，有事實足認被告在非搜索票所載之住宅內者", "有明顯事實足信為有人在住宅內犯罪而情形急迫者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00333', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '關於刑事程序之檢閱卷宗及證物制度，下列敘述何者正確？', '["被告於偵查中有檢閱卷宗及證物的權限", "被告於審判中得預納費用請求抄錄、重製或攝影卷宗及證物", "辯護人於偵查中之羈押審查程序，原則上得檢閱卷宗及證物並得抄錄或攝影", "被告於偵查中之羈押審查程序，有檢閱卷宗及證物的權限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
